<?php
 namespace WPAICG\Chat\Frontend\Shortcode; use WPAICG\Chat\Storage\BotStorage; use WP_Error; if (!defined('ABSPATH')) { exit; } class DataProvider { public static function get_bot_data(int $bot_id): array|WP_Error { $bot_post = get_post($bot_id); if (!$bot_post) { return new WP_Error('fetch_error', sprintf('[AIPKit Chatbot Error: Could not fetch post data for ID: %d]', $bot_id)); } if (!class_exists(\WPAICG\Chat\Storage\BotStorage::class)) { return new \WP_Error('internal_error', 'Cannot load bot data.'); } $bot_storage = new BotStorage(); $bot_settings = $bot_storage->get_chatbot_settings($bot_id); return ['post' => $bot_post, 'settings' => $bot_settings]; } }